165		{
166			// create a new message
167			msg = (vnf_p7_rx_message_t*)(vnf_p7_malloc(vnf_p7, sizeof(vnf_p7_rx_message_t)));
168			memset(msg, 0, sizeof(vnf_p7_rx_message_t));
169	
170			msg->sequence_number = sequence_number;
171			msg->num_segments_expected = m ? 255 : segment_number + 1;
172			msg->num_segments_received = 1;
173			msg->rx_hr_time = vnf_get_current_time_hr();
174	
175			msg->segments[segment_number].buffer = (uint8_t*)vnf_p7_malloc(vnf_p7, data_len);
176			memcpy(msg->segments[segment_number].buffer, data, data_len);
177			msg->segments[segment_number].length = data_len;
178	
179			// place the message at the head of the queue
180			msg->next = queue->msg_queue;
181			queue->msg_queue = msg;
182		}
183	
184		return msg;
185	}
